data:
.dark-mode .modal-content {
        background-color: var(--dark-card-bg) !important;
        color: var(--dark-text) !important;
    }
    .dark-mode .modal-content i, .dark-mode .modal-content li, .dark-mode .modal-content font {
        color: var(--dark-text) !important;
    }
    .dark-mode .modal-content font[style*="color:green"] {
        color: #238636 !important;
    }
    .dark-mode .modal-content font[style*="color:orange"] {
        color: #f39c12 !important;
    }
    .dark-mode .modal-content font[style*="color:red"] {
        color: #e74c3c !important;
    }
    .dark-mode .modal-content .fa-times-circle {
        color: var(--dark-text) !important;
    }



